package main

import "fmt"

type Position struct {
    X, Y int
}

func (p Position) Distance() int {
    if p.X > p.Y {
        return p.X - p.Y
    }
    return p.Y - p.X
}

type Entity struct {
    Position
    Name string
}

func main() {
    e := Entity{
        Position: Position{X: 10, Y: 5},
        Name:     "Monster",
    }
    fmt.Println(e.X, e.Y)         // promoted fields
    fmt.Println(e.Distance())     // promoted method
    fmt.Println(e.Name)
}
